/// Result codes returned by lifecycle calls.
enum le_result {
  LE_OK(0),

  /// null handle or bad argument
  LE_ERR_INVALID(-1),
  LE_ERR_ALREADY_RUNNING(-2),
  LE_ERR_NOT_RUNNING(-3),

  /// miniaudio failed to init/start the device
  LE_ERR_DEVICE(-4);

  final int value;
  const le_result(this.value);

  static le_result fromValue(int value) => switch (value) {
    0 => LE_OK,
    -1 => LE_ERR_INVALID,
    -2 => LE_ERR_ALREADY_RUNNING,
    -3 => LE_ERR_NOT_RUNNING,
    -4 => LE_ERR_DEVICE,
    _ => throw ArgumentError('Unknown value for le_result: $value'),
  };
}

/// Latency-harness phase, mirrored in le_snapshot.latency_state.
enum le_latency_state {
  LE_LATENCY_IDLE(0),

  /// impulse emitted, waiting for it to return
  LE_LATENCY_MEASURING(1),

  /// measured_latency_ms is valid
  LE_LATENCY_DONE(2),

  /// no loopback detected within the window
  LE_LATENCY_TIMEOUT(3);

  final int value;
  const le_latency_state(this.value);

  static le_latency_state fromValue(int value) => switch (value) {
    0 => LE_LATENCY_IDLE,
    1 => LE_LATENCY_MEASURING,
    2 => LE_LATENCY_DONE,
    3 => LE_LATENCY_TIMEOUT,
    _ => throw ArgumentError('Unknown value for le_latency_state: $value'),
  };
}

/// Per-track state machine, mirrored in le_snapshot.track_state.
enum le_track_state {
  LE_TRACK_EMPTY(0),

  /// capturing the first pass (defines the loop)
  LE_TRACK_RECORDING(1),

  /// summing input into the existing loop
  LE_TRACK_OVERDUBBING(2),
  LE_TRACK_PLAYING(3),

  /// buffer retained, playback halted
  LE_TRACK_STOPPED(4);

  final int value;
  const le_track_state(this.value);

  static le_track_state fromValue(int value) => switch (value) {
    0 => LE_TRACK_EMPTY,
    1 => LE_TRACK_RECORDING,
    2 => LE_TRACK_OVERDUBBING,
    3 => LE_TRACK_PLAYING,
    4 => LE_TRACK_STOPPED,
    _ => throw ArgumentError('Unknown value for le_track_state: $value'),
  };
}

/// Classification of a cable-free loopback path used to auto-measure latency.
/// All of these capture the *digital* round-trip (output → OS mixer → capture);
/// they exclude DAC/ADC converter latency, so they under-report the true analog
/// round-trip. A physical loopback cable remains the only true analog measure.
enum le_loopback_kind {
  LE_LOOPBACK_NONE(0),

  /// device backend's built-in output loopback
  LE_LOOPBACK_BACKEND(1),

  /// PulseAudio "Monitor of ..." source (Linux)
  LE_LOOPBACK_MONITOR(2),

  /// named virtual driver (BlackHole, VB-Cable, ...)
  LE_LOOPBACK_VIRTUAL(3);

  final int value;
  const le_loopback_kind(this.value);

  static le_loopback_kind fromValue(int value) => switch (value) {
    0 => LE_LOOPBACK_NONE,
    1 => LE_LOOPBACK_BACKEND,
    2 => LE_LOOPBACK_MONITOR,
    3 => LE_LOOPBACK_VIRTUAL,
    _ => throw ArgumentError('Unknown value for le_loopback_kind: $value'),
  };
}

/// Result of loopback detection. `device_name` is the capture device to open for
/// an auto-measurement (empty for the backend's built-in loopback, which the
/// duplex engine does not auto-route).
final class le_loopback_info extends ffi.Struct {
  /// 0/1
  @ffi.Int32()
  external int available;

  /// le_loopback_kind
  @ffi.Int32()
  external int kind;

  @ffi.Array.multi([256])
  external ffi.Array<ffi.Char> device_name;
}

/// Command codes posted into the engine's SPSC ring.
enum le_command_code {
  LE_CMD_NONE(0),
  LE_CMD_MEASURE_LATENCY(1),

  /// record / finalize-loop / toggle overdub
  LE_CMD_RECORD(2),

  /// halt playback (retain buffer)
  LE_CMD_STOP(3),

  /// resume playback
  LE_CMD_PLAY(4),

  /// erase the track, back to empty
  LE_CMD_CLEAR(5),

  /// remove the last overdub layer
  LE_CMD_UNDO(6),

  /// arg_f = 0..1
  LE_CMD_SET_VOLUME(7),

  /// arg_f = 0 (unmute) or 1 (mute)
  LE_CMD_SET_MUTE(8),

  /// arg_i = round-trip latency in frames
  LE_CMD_SET_RECORD_OFFSET(13),

  /// route a track's record sources (arg_f =
  /// track, arg_i = input bitmask)
  LE_CMD_SET_INPUT_MASK(14),

  /// route a track's playback destinations
  /// (arg_f = track, arg_i = output bitmask)
  LE_CMD_SET_OUTPUT_MASK(15),

  /// arg_i = track: arm a quantized record (fire at loop top)
  LE_CMD_ARM(16),

  /// arg_i = track: cancel a pending quantized record
  LE_CMD_DISARM(17),

  /// set a lane chain entry's type (and reset its DSP
  /// state). arg_i = (channel << 16) | (lane << 8) |
  /// index, arg_f = le_fx_type.
  LE_CMD_SET_LANE_FX(20),

  /// set a lane's active chain length.
  /// arg_i = (channel << 16) | (lane << 8) |
  /// count.
  LE_CMD_SET_LANE_FX_COUNT(21),

  /// arg_i = base loop length in frames: publish
  /// the master loop and start imported tracks
  LE_CMD_COMMIT_SESSION(23),

  /// lane records this input channel (-1 = none).
  /// arg_f = channel*LE_MAX_LANES + lane,
  /// arg_i = input channel (or -1).
  LE_CMD_SET_LANE_INPUT(26),

  /// lane playback destinations.
  /// arg_f = channel*LE_MAX_LANES + lane,
  /// arg_i = output bitmask.
  LE_CMD_SET_LANE_OUTPUT(27),

  /// lane playback gain.
  /// arg_i = channel*LE_MAX_LANES + lane,
  /// arg_f = 0..1.
  LE_CMD_SET_LANE_VOLUME(28),

  /// lane mute.
  /// arg_i = channel*LE_MAX_LANES + lane,
  /// arg_f = 0/1.
  LE_CMD_SET_LANE_MUTE(29),

  /// enable/disable a hardware input's monitor.
  /// arg_i = input, arg_f = enabled (0/1).
  LE_CMD_SET_MONITOR_INPUT(30),

  /// set a monitor lane's chain entry type
  /// (and reset its DSP state). arg_i =
  /// (input<<16)|(lane<<8)|index, arg_f = le_fx_type.
  LE_CMD_SET_MONITOR_LANE_FX(31),

  /// set a monitor lane's active chain length.
  /// arg_i = (input<<16)|(lane<<8)|count.
  LE_CMD_SET_MONITOR_LANE_FX_COUNT(32),

  /// monitor lane playback destinations.
  /// arg_f = input*LE_MAX_LANES+lane, arg_i = output bitmask.
  LE_CMD_SET_MONITOR_LANE_OUTPUT(33),

  /// monitor lane gain.
  /// arg_i = input*LE_MAX_LANES+lane, arg_f = 0..1.
  LE_CMD_SET_MONITOR_LANE_VOLUME(34),

  /// monitor lane mute.
  /// arg_i = input*LE_MAX_LANES+lane, arg_f = 0/1.
  LE_CMD_SET_MONITOR_LANE_MUTE(35);

  final int value;
  const le_command_code(this.value);

  static le_command_code fromValue(int value) => switch (value) {
    0 => LE_CMD_NONE,
    1 => LE_CMD_MEASURE_LATENCY,
    2 => LE_CMD_RECORD,
    3 => LE_CMD_STOP,
    4 => LE_CMD_PLAY,
    5 => LE_CMD_CLEAR,
    6 => LE_CMD_UNDO,
    7 => LE_CMD_SET_VOLUME,
    8 => LE_CMD_SET_MUTE,
    13 => LE_CMD_SET_RECORD_OFFSET,
    14 => LE_CMD_SET_INPUT_MASK,
    15 => LE_CMD_SET_OUTPUT_MASK,
    16 => LE_CMD_ARM,
    17 => LE_CMD_DISARM,
    20 => LE_CMD_SET_LANE_FX,
    21 => LE_CMD_SET_LANE_FX_COUNT,
    23 => LE_CMD_COMMIT_SESSION,
    26 => LE_CMD_SET_LANE_INPUT,
    27 => LE_CMD_SET_LANE_OUTPUT,
    28 => LE_CMD_SET_LANE_VOLUME,
    29 => LE_CMD_SET_LANE_MUTE,
    30 => LE_CMD_SET_MONITOR_INPUT,
    31 => LE_CMD_SET_MONITOR_LANE_FX,
    32 => LE_CMD_SET_MONITOR_LANE_FX_COUNT,
    33 => LE_CMD_SET_MONITOR_LANE_OUTPUT,
    34 => LE_CMD_SET_MONITOR_LANE_VOLUME,
    35 => LE_CMD_SET_MONITOR_LANE_MUTE,
    _ => throw ArgumentError('Unknown value for le_command_code: $value'),
  };
}

/// A hardware audio device discovered by enumeration (le_enumerate_*).
///
/// `id` is an opaque, backend-specific token suitable for pinning a device via
/// le_config.playback_device_id / capture_device_id. On every string-id backend
/// (CoreAudio, ALSA, PulseAudio, sndio) it is the device's native id string; it
/// round-trips byte-for-byte back into le_config. `name` is the human-readable
/// label; `is_default` marks the system default for that direction.
final class le_device_info extends ffi.Struct {
  @ffi.Array.multi([256])
  external ffi.Array<ffi.Char> id;

  @ffi.Array.multi([256])
  external ffi.Array<ffi.Char> name;

  /// 0/1
  @ffi.Int32()
  external int is_default;

  /// 0 = unknown (miniaudio); an ASIO probe fills it
  @ffi.Int32()
  external int input_channels;

  /// 0 = unknown
  @ffi.Int32()
  external int output_channels;

  /// ASIO-only: the driver's selectable buffer sizes and supported sample rates,
  /// probed by le_enumerate_asio_drivers so the UI can offer the driver's real
  /// options instead of a generic list. Count 0 for non-ASIO devices (the UI
  /// then keeps its default lists). Sizes/rates are ascending; the buffer set
  /// always includes the driver's preferred size.
  @ffi.Array.multi([8])
  external ffi.Array<ffi.Int32> asio_buffer_sizes;

  @ffi.Int32()
  external int asio_buffer_count;

  @ffi.Array.multi([8])
  external ffi.Array<ffi.Int32> asio_sample_rates;

  @ffi.Int32()
  external int asio_sample_rate_count;
}

/// Requested device configuration. Any channel field set to 0 uses the device
/// default; counts are clamped to LE_MAX_CHANNELS.
final class le_config extends ffi.Struct {
  @ffi.Int32()
  external int sample_rate;

  @ffi.Int32()
  external int buffer_frames;

  /// per-track buffer cap; 0 => default (8 min @ sr)
  @ffi.Int32()
  external int max_loop_frames;

  /// 1 = capture from a detected loopback device
  @ffi.Int32()
  external int use_loopback_capture;

  /// hardware capture channels (0 => device default)
  @ffi.Int32()
  external int input_channels;

  /// hardware playback channels (0 => device default)
  @ffi.Int32()
  external int output_channels;

  /// Pin a specific device by id (an `id` from le_enumerate_*). An empty string
  /// opens the system default (the unchanged behaviour). use_loopback_capture
  /// overrides capture_device_id when a loopback device is detected.
  @ffi.Array.multi([256])
  external ffi.Array<ffi.Char> playback_device_id;

  @ffi.Array.multi([256])
  external ffi.Array<ffi.Char> capture_device_id;

  /// le_audio_backend to open; 0 (LE_BACKEND_MINIAUDIO) selects the default
  /// miniaudio path. On Windows the engine forces ASIO.
  @ffi.Int32()
  external int backend;

  /// Selected ASIO driver name (used by the ASIO backend). Empty and
  /// ignored on the miniaudio path.
  @ffi.Array.multi([256])
  external ffi.Array<ffi.Char> asio_driver;
}

/// Per-lane state published via le_engine_get_lane: one recordable input lane of
/// a track. A lane records exactly one hardware input (input_channel, -1 = none)
/// into its own clean mono buffer and plays back to the outputs in output_mask,
/// scaled by volume and gated by muted. length_frames is the lane's recorded
/// length (all lanes of a track share the same length via the one transport).
final class le_lane_snapshot extends ffi.Struct {
  /// hardware input this lane records (-1 = none)
  @ffi.Int32()
  external int input_channel;

  /// bitmask of output channels this lane plays to
  @ffi.Uint32()
  external int output_mask;

  /// 0..1
  @ffi.Float()
  external double volume;

  /// 0/1
  @ffi.Int32()
  external int muted;

  /// frames captured into this lane's buffer
  @ffi.Int32()
  external int length_frames;

  /// 0..1
  @ffi.Float()
  external double rms;

  /// 0..1
  @ffi.Float()
  external double peak;
}

/// Per-track state published in le_snapshot.tracks.
///
/// A track is a multi-lane container: it owns the transport (state, multiple,
/// undo/redo depth) and up to lane_count lanes. The volume/muted/length/
/// input_mask/output_mask/rms/peak fields mirror lane 0 for backward
/// compatibility (a track always has at least one lane); per-lane state is read
/// with le_engine_get_lane.
final class le_track_snapshot extends ffi.Struct {
  /// le_track_state
  @ffi.Int32()
  external int state;

  /// lane 0 volume, 0..1
  @ffi.Float()
  external double volume;

  /// lane 0 mute, 0/1
  @ffi.Int32()
  external int muted;

  /// frames captured (== multiple * master length)
  @ffi.Int32()
  external int length_frames;

  /// track length in whole base loops (>= 1)
  @ffi.Int32()
  external int multiple;

  /// available undo steps (overdub layers)
  @ffi.Int32()
  external int undo_depth;

  /// available redo steps
  @ffi.Int32()
  external int redo_depth;

  /// lane 0 RMS, 0..1
  @ffi.Float()
  external double rms;

  /// lane 0 peak, 0..1
  @ffi.Float()
  external double peak;

  /// lane 0 input as a bitmask (1 << input_channel, or 0
  /// when lane 0 records no input)
  @ffi.Uint32()
  external int input_mask;

  /// lane 0 output mask
  @ffi.Uint32()
  external int output_mask;

  /// number of active lanes (1..LE_MAX_LANES)
  @ffi.Int32()
  external int lane_count;
}

/// Lock-free snapshot of engine state, published by the audio thread and read by
/// Dart on a render-rate timer. Fields are individually atomic; readers may see
/// a one-frame-stale mix across fields, which is fine for metering/UI.
final class le_snapshot extends ffi.Struct {
  /// 0/1: device is open and the callback is live
  @ffi.Int32()
  external int running;

  /// 0/1: the pinned (or default) device is currently present. DISTINCT from
  /// `running`: a device can be lost (device_present == 0) while the engine
  /// object still "runs" until it is restarted. Set from the RT-adjacent device
  /// notification callback; the Dart layer derives a higher-level isConnected
  /// from it and drives any reconnection (no reconnection happens in native).
  @ffi.Int32()
  external int device_present;

  @ffi.Int32()
  external int sample_rate;

  @ffi.Int32()
  external int buffer_frames;

  /// negotiated hardware capture channels
  @ffi.Int32()
  external int input_channels;

  /// negotiated hardware playback channels
  @ffi.Int32()
  external int output_channels;

  /// Bitmask of input channels excluded from recording/monitoring/routing
  /// because their hardware (Core Audio) label matches "loopback". Such channels
  /// are skipped in the capture average and in monitoring, and are stripped from
  /// any track input mask. Always 0 off macOS / when no label matches.
  @ffi.Uint32()
  external int excluded_input_mask;

  /// total frames seen by the callback
  @ffi.Uint64()
  external int frames_processed;

  /// reserved; xrun detection lands later (0)
  @ffi.Uint32()
  external int xrun_count;

  /// 0..1
  @ffi.Float()
  external double input_rms;

  /// 0..1
  @ffi.Float()
  external double input_peak;

  /// 0..1
  @ffi.Float()
  external double output_rms;

  /// le_latency_state
  @ffi.Int32()
  external int latency_state;

  /// valid when latency_state == LE_LATENCY_DONE
  @ffi.Double()
  external double measured_latency_ms;

  /// 0 until the first recording is finalized
  @ffi.Int32()
  external int master_length_frames;

  /// current loop playhead
  @ffi.Int32()
  external int master_position_frames;

  /// Record-offset latency compensation (frames). Recorded/overdubbed input is
  /// written this many frames earlier in the loop so it aligns with what the
  /// player heard. Auto-set by a latency measurement; manually overridable.
  @ffi.Int32()
  external int record_offset_frames;

  /// le_audio_backend actually running (negotiated). On Windows this is always
  /// ASIO; on macOS/Linux it is the miniaudio backend.
  @ffi.Int32()
  external int active_backend;

  /// number of usable tracks (<= LE_MAX_TRACKS)
  @ffi.Int32()
  external int track_count;

  @ffi.Array.multi([8])
  external ffi.Array<le_track_snapshot> tracks;
}

final class le_engine extends ffi.Opaque {}

const int LE_MAX_CHANNELS = 32;

const int LE_FX_MAX = 8;

const int LE_FX_PARAMS = 3;

const int LE_MAX_TRACKS = 8;

const int LE_MAX_INPUTS = 8;

const int LE_MAX_LANES = 8;

const int LE_VIZ_POINTS = 512;
